// Merge Blueprint Results + Deterministic FAQ Enforcement (STATELESS)
// IMPORTANT: Code node must be set to "Run Once for All Items"

const items = $input.all();

// If upstream returned a single error item, just pass it through
if (items.length === 1 && items[0]?.json?.ok === false) {
  return items;
}

// Basic validation
if (!items.length) {
  return [{ json: { ok: false, status: 500, error: "No items received to merge" } }];
}

const first = items[0].json || {};
const request_id = first.request_id || null;

// ------------------------------
// Helpers
// ------------------------------
function clamp(n, min, max) {
  return Math.max(min, Math.min(max, n));
}

function normalizeText(value) {
  return String(value || "")
    .toLowerCase()
    .replace(/\s+/g, " ")
    .trim();
}

function ensureParagraph(answer) {
  const trimmed = String(answer || "").trim();
  if (!trimmed) return "";
  if (/<p[\s>]/i.test(trimmed)) {
    return trimmed;
  }
  return `<p>${trimmed}</p>`;
}

function faqRangeForPageType(pageType) {
  if (pageType === "service") return { min: 4, max: 6 };
  if (pageType === "service_area") return { min: 3, max: 5 };
  if (pageType === "services_overview" || pageType === "service_areas_overview") return { min: 3, max: 4 };
  // default for other non-homepage pages
  return { min: 3, max: 4 };
}

const faqEligible = new Set([
  "service",
  "service_area",
  "services_overview",
  "service_areas_overview"
]);

function deterministicSlice(pool, seedInt, count) {
  if (!pool.length) return [];
  const start = Math.abs(seedInt) % pool.length;
  const out = [];
  for (let i = 0; i < count; i++) {
    out.push(pool[(start + i) % pool.length]);
  }
  return out;
}

const ctaDescriptorByPageType = {
  homepage: "your project",
  service: "this service",
  service_area: "local service",
  services_overview: "our services",
  service_areas_overview: "coverage in your area",
  about: "working with our team"
};

const ctaVariants = [
  (desc) => `Get a fast, local response about ${desc}.`,
  (desc) => `Talk with a specialist about ${desc} today.`,
  (desc) => `Schedule a quick, no-pressure walkthrough for ${desc}.`,
  (desc) => `Get clear timing and next steps for ${desc}.`,
  (desc) => `Plan ${desc} with a trusted local team.`,
  (desc) => `Get answers and a simple plan for ${desc}.`,
  (desc) => `Start with a fast estimate for ${desc}.`,
  (desc) => `Lock in a convenient window for ${desc}.`
];

function buildCtaSupport(pageType, seed) {
  const desc = ctaDescriptorByPageType[pageType] || "your project";
  const idx = Math.abs(seed) % ctaVariants.length;
  return ctaVariants[idx](desc);
}

// ------------------------------
// 1) Find homepage item + FAQ pool
// ------------------------------
const homepageItem = items.find(i => i?.json?.page_type === "homepage");
let globalPool = [];

// Prefer FAQ pool generated on homepage in this run
if (homepageItem?.json?.updates?.length) {
  const homepageFaq = homepageItem.json.updates.filter(u => u?.target === "faq");
  if (homepageFaq.length) {
    globalPool = homepageFaq.map(u => ({
      question: u?.fields?.question || "",
      answer: ensureParagraph(u?.fields?.answer || "")
    })).filter(x => x.question && x.answer);
  }
}

// Fallback: if WP payload already included a pool
if (!globalPool.length && Array.isArray(first.global_faq_pool) && first.global_faq_pool.length) {
  globalPool = first.global_faq_pool
    .map(x => ({ question: x?.question || "", answer: ensureParagraph(x?.answer || "") }))
    .filter(x => x.question && x.answer);
}

// ------------------------------
// 2) Enforce FAQ on each non-homepage item BEFORE merge
// ------------------------------
for (const it of items) {
  const j = it.json || {};
  if (!j.ok || !Array.isArray(j.updates)) continue;

  const pageType = j.page_type || null;

  // Homepage: allow as-is (it is canonical generator)
  if (pageType === "homepage") continue;

  if (!faqEligible.has(pageType)) {
    j.updates = j.updates.filter(u => u?.target !== "faq");
    continue;
  }

  // If no pool exists, do nothing (don’t invent FAQs here)
  if (!globalPool.length) {
    // still strip any LLM-generated FAQs to avoid random drift
    j.updates = j.updates.filter(u => u?.target !== "faq");
    continue;
  }

  // Strip any LLM FAQ attempts
  j.updates = j.updates.filter(u => u?.target !== "faq");

  const seedInt = parseInt(j.variation_seed || first.variation_seed || "1", 10) || 1;
  const { min, max } = faqRangeForPageType(pageType);

  // deterministic count in range
  const span = (max - min + 1);
  const count = clamp(min + (Math.abs(seedInt) % span), min, max);

  const sliced = deterministicSlice(globalPool, seedInt, count);

  // Inject deterministic FAQs
  for (const faq of sliced) {
    j.updates.push({
      target: "faq",
      id: null,
      fields: {
        question: faq.question,
        answer: ensureParagraph(faq.answer)
      }
    });
  }
}

// ------------------------------
// 3) Enforce unique CTA supporting sentences across pages
// ------------------------------
const ctaSeen = new Set();

items.forEach((it, itemIndex) => {
  const j = it.json || {};
  if (!j.ok || !Array.isArray(j.updates)) return;

  const pageType = j.page_type || null;

  for (const update of j.updates) {
    const fields = update?.fields;
    if (!fields || typeof fields !== "object") continue;

    for (const key of Object.keys(fields)) {
      if (!key.endsWith(".cta_subheadline_secondary")) continue;

      const raw = typeof fields[key] === "string" ? fields[key].trim() : "";
      let normalized = normalizeText(raw);

      if (pageType !== "homepage" && (!raw || ctaSeen.has(normalized))) {
        let attempt = 0;
        let candidate = "";
        let candidateNorm = "";
        do {
          candidate = buildCtaSupport(pageType, itemIndex + attempt + 1);
          candidateNorm = normalizeText(candidate);
          attempt += 1;
        } while (candidateNorm === "" || ctaSeen.has(candidateNorm));
        fields[key] = candidate;
        normalized = candidateNorm;
      }

      if (normalized !== "") {
        ctaSeen.add(normalized);
      }
    }
  }
});

// ------------------------------
// 4) Merge all updates into one response payload
// ------------------------------
const mergedUpdates = [];
for (const it of items) {
  const j = it.json || {};
  if (j.ok && Array.isArray(j.updates)) {
    mergedUpdates.push(...j.updates);
  }
}

return [{
  json: {
    ok: true,
    request_id,
    updates: mergedUpdates
  }
}];

function pickRaw(input) {
  if (typeof input === "string") return input;
  if (typeof input?.text === "string") return input.text;
  if (typeof input?.output === "string") return input.output;
  if (typeof input?.response === "string") return input.response;
  if (typeof input?.data?.text === "string") return input.data.text;
  if (typeof input?.message?.content === "string") return input.message.content;
  return input;
}

function deepClean(value) {
  if (typeof value === "string") {
    return value
      .replace(/
/g, "
")
      .replace(//g, "
");
  }

  if (Array.isArray(value)) return value.map(deepClean);

  if (value && typeof value === "object") {
    const cleaned = {};
    for (const key in value) cleaned[key] = deepClean(value[key]);
    return cleaned;
  }

  return value;
}

function stripHtml(value) {
  return String(value || "")
    .replace(/<[^>]*>/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function trimToWords(value, maxWords) {
  const text = stripHtml(value);
  if (!text) return "";
  const words = text.split(/\s+/);
  if (words.length <= maxWords) return words.join(" ");
  return words.slice(0, maxWords).join(" ");
}

function pickShortDesc(updates) {
  const suffixes = [
    ".hero_subheadline",
    ".hero_supporting_text",
    ".section_intro",
    ".section_body",
    ".section_body_secondary"
  ];
  for (const update of updates) {
    const fields = update?.fields;
    if (!fields || typeof fields !== "object") continue;
    const keys = Object.keys(fields);
    for (const suffix of suffixes) {
      const key = keys.find(k => k.toLowerCase().endsWith(suffix));
      if (!key) continue;
      const value = trimToWords(fields[key], 28);
      if (value) return value;
    }
  }
  return "";
}

function findPostMetaId(updates) {
  const hit = updates.find(u => u?.target === "post_meta" && u?.id);
  return hit?.id || null;
}

function parseJsonSafely(raw) {
  if (typeof raw !== "string") {
    return { ok: true, value: raw };
  }

  const candidates = [];
  const trimmed = raw.trim();
  candidates.push(trimmed);

  const fence = trimmed.match(/```(?:json)?\s*([\s\S]*?)\s*```/i);
  if (fence && fence[1]) candidates.push(fence[1].trim());

  const firstBrace = trimmed.indexOf('{');
  const lastBrace = trimmed.lastIndexOf('}');
  if (firstBrace >= 0 && lastBrace > firstBrace) {
    candidates.push(trimmed.slice(firstBrace, lastBrace + 1));
  }

  let lastError = null;
  for (const candidate of candidates) {
    try {
      return { ok: true, value: JSON.parse(candidate) };
    } catch (e) {
      lastError = e;
    }
  }

  return { ok: false, error: String(lastError?.message || 'Unable to parse JSON') };
}

const inputCtx = $json && typeof $json === 'object' ? $json : {};
const requestIdHint = inputCtx.request_id || null;
const pageTypeHint = inputCtx.page_type || null;
const primaryHint = inputCtx.primary_keyword || '';
const secondaryHint = Array.isArray(inputCtx.secondary_keywords) ? inputCtx.secondary_keywords : [];
const businessHint = inputCtx.business_name || '';
const cityHint = inputCtx.city_region || '';
const styleHint = inputCtx.style_profile?.id || inputCtx.style_profile_id || '';

const raw = pickRaw($json);
const parsedResult = parseJsonSafely(raw);
if (!parsedResult.ok) {
  return [{
    json: {
      ok: false,
      status: 500,
      error: "Invalid JSON from LLM",
      details: parsedResult.error,
      page_type: pageTypeHint,
      request_id: requestIdHint,
      raw_preview: (typeof raw === "string") ? raw.slice(0, 800) : null
    }
  }];
}

const parsed = parsedResult.value;

if (!parsed || parsed.ok !== true || !Array.isArray(parsed.updates)) {
  return [{
    json: {
      ok: false,
      status: 422,
      error: "Invalid payload",
      page_type: pageTypeHint,
      request_id: requestIdHint,
      parsed_preview: parsed
    }
  }];
}

const cleaned = deepClean(parsed);
let updates = (Array.isArray(cleaned.updates) ? cleaned.updates : []).map(u => ({
  ...u,
  fields: u?.fields ?? u?.data ?? {}
}));

const pageType = cleaned.page_type || pageTypeHint || null;

if (pageType && pageType !== "homepage") {
  updates = updates.map(u => {
    if (!u.fields) return u;
    const safeFields = { ...u.fields };
    delete safeFields.cta_headline;
    delete safeFields.cta_subheadline;
    delete safeFields.cta_primary_override;
    delete safeFields.cta_secondary_override;
    return { ...u, fields: safeFields };
  });
}

const meta = (cleaned.meta && typeof cleaned.meta === "object") ? cleaned.meta : {};
if (!meta.primary_keyword && primaryHint) meta.primary_keyword = primaryHint;
if (!meta.secondary_keywords && secondaryHint.length) meta.secondary_keywords = secondaryHint;
if (!meta.business_name && businessHint) meta.business_name = businessHint;
if (!meta.city_region && cityHint) meta.city_region = cityHint;
if (!meta.style_profile_id && styleHint) meta.style_profile_id = styleHint;

if (pageType === "service") {
  const postId = findPostMetaId(updates);
  const shortDesc = pickShortDesc(updates);
  if (postId && shortDesc) {
    updates.push({
      target: "service_meta",
      id: postId,
      fields: {
        lf_service_short_desc: shortDesc
      }
    });
  }
}

return [{
  json: {
    ok: true,
    request_id: cleaned.request_id || requestIdHint,
    page_type: pageType,
    meta,
    updates
  }
}];

// Quality Gate + SEO Enforcement (post-generation)
// Fails the workflow if key quality rules are not met.

const items = $input.all();

if (!items.length) {
  return [{ json: { ok: false, status: 500, error: "No items for quality gate" } }];
}

const upstreamFailures = items
  .map(i => i?.json || {})
  .filter(j => j && j.ok === false);

if (upstreamFailures.length) {
  return [{
    json: {
      ok: false,
      status: 422,
      error: "Parse/validation failed for one or more blueprints",
      failed_count: upstreamFailures.length,
      total_items: items.length,
      details: upstreamFailures.slice(0, 8).map(f => ({
        page_type: f.page_type || null,
        error: f.error || 'unknown_error',
        details: f.details || null,
        raw_preview: typeof f.raw_preview === 'string' ? f.raw_preview.slice(0, 240) : null
      }))
    }
  }];
}

function normalizeText(value) {
  return String(value || "")
    .toLowerCase()
    .replace(/\s+/g, " ")
    .trim();
}

function wordCount(value) {
  const text = String(value || "").trim();
  if (!text) return 0;
  return text.split(/\s+/).length;
}

function containsKeyword(value, keyword) {
  if (!keyword) return false;
  const escaped = keyword.replace(/[.*+?^${}()|[\]\]/g, "\$&");
  const re = new RegExp(`\b${escaped}\b`, "i");
  return re.test(String(value || ""));
}

function injectKeyword(fields, keyword, preferredSuffix) {
  const priorityKeys = [
    ".hero_headline",
    ".hero_subheadline",
    ".hero_supporting_text",
    ".section_heading",
    ".section_intro",
    ".section_body",
    ".section_body_secondary"
  ];

  const keys = Object.keys(fields || {});
  for (const suffix of priorityKeys) {
    const key = keys.find(k => k.toLowerCase().endsWith(suffix));
    if (!key) continue;
    const value = String(fields[key] || "").trim();
    if (!value) {
      fields[key] = keyword;
      return true;
    }
    if (!containsKeyword(value, keyword)) {
      fields[key] = `${value} ${preferredSuffix || keyword}`.trim();
      return true;
    }
  }
  for (const key of keys) {
    if (typeof fields[key] !== "string") continue;
    const value = String(fields[key] || "").trim();
    if (!containsKeyword(value, keyword)) {
      fields[key] = `${value} ${preferredSuffix || keyword}`.trim();
      return true;
    }
  }
  return false;
}

function appendSentence(value, sentence) {
  const trimmed = String(value || "").trim();
  if (!trimmed) return sentence;
  const spacer = /[.!?]$/.test(trimmed) ? " " : ". ";
  return `${trimmed}${spacer}${sentence}`.trim();
}

function enforceUniqueness(fields, cityRegion, businessName) {
  const seen = new Map();
  const keys = Object.keys(fields || {});
  for (const key of keys) {
    if (typeof fields[key] !== "string") continue;
    const value = String(fields[key] || "").trim();
    if (!value) continue;
    const normalized = normalizeText(value);
    if (seen.has(normalized)) {
      const suffix = cityRegion ? ` in ${cityRegion}` : (businessName ? ` with ${businessName}` : "");
      fields[key] = `${value}${suffix}`.trim();
    } else {
      seen.set(normalized, true);
    }
  }
}

function minWordTarget(pageType) {
  if (pageType === "homepage") return 140;
  if (["sitemap", "privacy", "terms", "thank_you"].includes(pageType)) return 60;
  if (["contact", "reviews", "blog", "about", "services_overview", "service_areas_overview"].includes(pageType)) return 80;
  return 100;
}

const errors = [];

for (const item of items) {
  const json = item.json || {};
  if (!json.ok || !Array.isArray(json.updates)) continue;

  const meta = json.meta || {};
  const primaryKeyword = String(meta.primary_keyword || "").trim();
  const secondaryKeywords = Array.isArray(meta.secondary_keywords) ? meta.secondary_keywords : [];
  const businessName = String(meta.business_name || "").trim();
  const cityRegion = String(meta.city_region || "").trim();
  const pageType = json.page_type || "unknown";

  let totalWords = 0;
  let primaryFound = false;
  let secondaryFound = false;

  for (const update of json.updates) {
    const fields = update?.fields || {};
    for (const key of Object.keys(fields)) {
      const value = fields[key];
      if (typeof value === "string") {
        totalWords += wordCount(value);
        if (primaryKeyword && containsKeyword(value, primaryKeyword)) primaryFound = true;
        if (!secondaryFound && secondaryKeywords.length) {
          secondaryFound = secondaryKeywords.some(sk => containsKeyword(value, sk));
        }
      }
    }
  }

  if (primaryKeyword && !primaryFound) {
    let injected = false;
    for (const update of json.updates) {
      if (injectKeyword(update.fields, primaryKeyword)) {
        injected = true;
        break;
      }
    }
    if (!injected) errors.push(`Missing primary keyword on ${pageType}.`);
  }

  if (secondaryKeywords.length && !secondaryFound) {
    const pick = String(secondaryKeywords[0] || "").trim();
    if (pick) {
      let injected = false;
      for (const update of json.updates) {
        const fields = update?.fields || {};
        const keys = Object.keys(fields);
        const key = keys.find(k => /section_body|section_intro|hero_supporting_text/i.test(k));
        if (!key || typeof fields[key] !== "string") continue;
        fields[key] = appendSentence(fields[key], `${pick} is available for local homeowners.`);
        injected = true;
        break;
      }
      if (!injected) errors.push(`Missing secondary keyword on ${pageType}.`);
    }
  }

  for (const update of json.updates) {
    enforceUniqueness(update.fields, cityRegion, businessName);
  }

  const minTotal = minWordTarget(pageType);
  if (totalWords < minTotal) errors.push(`Low content volume on ${pageType} (${totalWords} words).`);
}

if (errors.length) {
  return [{
    json: {
      ok: false,
      status: 422,
      error: "Quality gate failed",
      details: errors
    }
  }];
}

return items;

// Split FULL payload into ONE-blueprint-per-item for the LLM
// Hardened: preserves full blueprint structure including sections

const raw = $json.body ?? $json;
const payload = raw.body ?? raw;

if (!payload || !Array.isArray(payload.blueprints)) {
  return [{
    json: {
      ok: false,
      status: 400,
      error: "Invalid payload: missing blueprints[]"
    }
  }];
}

const homepageBlueprint = payload.blueprints.find(bp => {
  const pageType = bp?.page_type || bp?.page;
  return pageType === "homepage";
});

const blueprintFaqPool = Array.isArray(homepageBlueprint?.faqs)
  ? homepageBlueprint.faqs
  : [];
const payloadFaqPool = Array.isArray(payload.global_faq_pool)
  ? payload.global_faq_pool
  : [];

const system_message = typeof payload.system_message === "string"
  ? payload.system_message
  : "";
const faq_strategy = payload.faq_strategy ?? {};
const cta_strategy = payload.cta_strategy ?? {};
const workflowData = $getWorkflowStaticData('global') || {};
const research_document = workflowData.research_document && typeof workflowData.research_document === 'object'
  ? workflowData.research_document
  : {};

function buildResearchContext(doc) {
  if (!doc || typeof doc !== 'object') return {};
  const allowed = [
    'brand_positioning',
    'conversion_strategy',
    'voice_guidelines',
    'seo_strategy',
    'faq_strategy',
