const webhook = $node["Webhook"].json || {};
const jobId = webhook.job_id || webhook.body?.job_id || $json?.job_id || null;
const callbackUrl = webhook.callback_url || webhook.body?.callback_url || $json?.callback_url || "";
const requestId = $json?.request_id || webhook.request_id || webhook.body?.request_id || "";
const authHeader = webhook.headers?.authorization || webhook.headers?.Authorization || "";

const callbackBodyObj = {
  ...$json,
  job_id: jobId,
  request_id: requestId,
  callback_url: callbackUrl
};

return [{
  json: {
    ...callbackBodyObj,
    callback_payload: { payload: JSON.stringify(callbackBodyObj) },
    callback_auth_header: authHeader
  }
}];

const items = $input.all();
if (!items.length) {
  return [{ json: { ok: false, status: 500, error: 'No items for global completeness gate.' } }];
}

const upstreamFailures = items
  .map(item => item?.json || {})
  .filter(j => j && j.ok === false);

if (upstreamFailures.length) {
  const firstFailure = upstreamFailures[0] || {};
  const upstreamError = String(firstFailure.error || 'Unknown upstream generation error').trim();
  const detailSource = firstFailure.details ?? firstFailure.raw_preview ?? '';
  const upstreamDetails = typeof detailSource === 'string'
    ? detailSource.trim()
    : JSON.stringify(detailSource || {});
  const detailText = upstreamDetails ? ` | details: ${upstreamDetails}` : '';
  throw new Error(`Upstream generation failed before completeness checks: ${upstreamError}${detailText}`);
}

function wordCount(v) {
  const t = String(v || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
  return t ? t.split(' ').length : 0;
}

function normalized(v) {
  return String(v || '').toLowerCase().replace(/\s+/g, ' ').trim();
}

const genericFlags = [
  'short overview of',
  'sample project created during site generation',
  'what to expect',
  'placeholder',
  'lorem ipsum'
];

function hasGenericText(text) {
  const n = normalized(text);
  return genericFlags.some(flag => n.includes(flag));
}

function toBool(value, fallback = false) {
  if (value === true || value === 1 || value === '1') return true;
  if (value === false || value === 0 || value === '0') return false;
  return fallback;
}

const webhook = $node['Webhook'].json || {};
const payload = webhook.body ?? webhook;
const manifestScopeMode = String(payload.generation_scope || '').trim().toLowerCase();
const scopeObject = (payload.generation_scope && typeof payload.generation_scope === 'object')
  ? payload.generation_scope
  : {};

const scope = manifestScopeMode === 'homepage_only'
  ? {
      homepage: true,
      services: false,
      service_areas: false,
      core_pages: false,
      blog_posts: false,
      projects: false
    }
  : {
      homepage: toBool(scopeObject.homepage, true),
      services: toBool(scopeObject.services, true),
      service_areas: toBool(scopeObject.service_areas, true),
      core_pages: toBool(scopeObject.core_pages, true),
      blog_posts: toBool(scopeObject.blog_posts, true),
      projects: toBool(scopeObject.projects, true)
    };

const warnings = [];
const pageTypeCounts = {};

const isMergedPayload = items.length === 1
  && Array.isArray(items[0]?.json?.updates)
  && String(items[0]?.json?.page_type || '').trim() === '';

if (isMergedPayload) {
  const merged = items[0].json || {};
  const updates = Array.isArray(merged.updates) ? merged.updates : [];
  const targetCounts = {};

  for (const update of updates) {
    const target = String(update?.target || 'unknown').trim() || 'unknown';
    targetCounts[target] = (targetCounts[target] || 0) + 1;
  }

  const homepageProduced = updates.some(update =>
    String(update?.target || '') === 'options' && String(update?.id || '') === 'homepage'
  );

  const nonHomepageNonFaqUpdates = updates.filter(update => {
    const target = String(update?.target || '');
    const id = String(update?.id || '');
    if (target === 'faq') return false;
    if (target === 'options' && id === 'homepage') return false;
    return true;
  });

  if (scope.homepage && !homepageProduced) {
    throw new Error('Global completeness gate failed: homepage scope is enabled but merged updates did not include options/homepage fields.');
  }

  if ((scope.services || scope.service_areas || scope.core_pages || scope.blog_posts || scope.projects)
      && nonHomepageNonFaqUpdates.length === 0) {
    warnings.push(`Scope mismatch: non-homepage pages requested but merged updates only include homepage/faq. update_targets=${JSON.stringify(targetCounts)}`);
  }

  merged.quality_warnings = Array.isArray(merged.quality_warnings)
    ? Array.from(new Set(merged.quality_warnings.concat(warnings)))
    : warnings;
  merged.page_type_counts = merged.page_type_counts || {};
  merged.update_target_counts = targetCounts;
  merged.scope_mismatch = warnings.length > 0;
  return [{ json: merged }];
}

for (const item of items) {
  const j = item.json || {};
  const pageType = String(j.page_type || '').trim();
  if (pageType) {
    pageTypeCounts[pageType] = (pageTypeCounts[pageType] || 0) + 1;
  }

  if (!j.ok || !Array.isArray(j.updates) || !j.updates.length) {
    warnings.push(`Missing updates for page_type=${pageType || 'unknown'}`);
    continue;
  }

  let pageWords = 0;
  let hasPrimary = false;
  const primary = String(j?.meta?.primary_keyword || '').trim();

  for (const update of j.updates) {
    if (!update || !update.fields || typeof update.fields !== 'object') continue;
    for (const key of Object.keys(update.fields)) {
      const value = update.fields[key];
      if (typeof value !== 'string') continue;
      pageWords += wordCount(value);
      if (primary && normalized(value).includes(normalized(primary))) {
        hasPrimary = true;
      }
      if (hasGenericText(value)) {
        warnings.push(`Generic placeholder phrase found in ${pageType || 'unknown'} field ${key}`);
      }
    }
  }

  if (primary && !hasPrimary) {
    warnings.push(`Primary keyword missing in content body for ${pageType || 'unknown'}`);
  }

  const minWords = pageType === 'post' ? 450 : (pageType === 'homepage' ? 180 : 120);
  if (pageWords < minWords) {
    warnings.push(`Low content volume for ${pageType || 'unknown'} (${pageWords} words, min ${minWords})`);
  }
}

if (scope.homepage && !pageTypeCounts.homepage) {
  throw new Error('Global completeness gate failed: homepage scope is enabled but no homepage blueprints were produced.');
}
if (scope.services && !pageTypeCounts.service) {
  warnings.push('Scope mismatch: services enabled but no service blueprints were produced.');
}
if (scope.service_areas && !pageTypeCounts.service_area) {
  warnings.push('Scope mismatch: service_areas enabled but no service_area blueprints were produced.');
}
if (scope.core_pages) {
  const required = ['about', 'contact'];
  for (const type of required) {
    if (!pageTypeCounts[type]) {
      warnings.push(`Scope mismatch: core_pages enabled but missing page_type=${type}`);
    }
  }
}
if (scope.blog_posts) {
  const blogCount = pageTypeCounts.post || 0;
  if (blogCount < 5) {
    warnings.push(`Scope mismatch: blog_posts enabled but only ${blogCount} blog blueprints were produced (expected at least 5).`);
  }
}

for (const item of items) {
  if (!item.json || typeof item.json !== 'object') {
    item.json = {};
  }
  item.json.quality_warnings = warnings;
  item.json.page_type_counts = pageTypeCounts;
  item.json.scope_mismatch = warnings.some(w => String(w).startsWith('Scope mismatch:'));
}

return items;
